pub fn push_first_slug(tags: &mut Vec<String>) {
    let first = tags.first().unwrap_or(&String::from("default"));
    tags.push(first.to_lowercase());
}

pub fn push_first_slug(tags: &mut Vec<String>) {
    let first = tags.first().cloned().unwrap_or_else(|| "default".to_string());
    tags.push(first.to_lowercase());
}
